mod tests {
    use super::*;

    #[test]
    fn test_land_value_new() {
        let lv = LandValueHeatmap::new();
        assert_eq!(lv.values.len(), HEATMAP_SIZE * HEATMAP_SIZE);
        // Todos deberían ser 10.0
        for v in lv.values.iter() {
            assert!((*v - 10.0).abs() < 0.001);
        }
    }

    #[test]
